#include <bits/stdc++.h>
using namespace std;

int s[15],a[15][5],ds[1<<24],dt[1<<24],ls[1<<24],lsb[1<<24],lt[1<<24],ltb[1<<24],path[25],top;
queue<int> qs,qt;

int chg(int x,int p,int k){
    int num=((x>>p*2)&3);
    return x-(num<<p*2)+(((num+k+4)%4)<<p*2);
}

int main(){
    int st=0;
    for(int i=0;i<12;i++){
        scanf("%d%d%d%d%d",&s[i],&a[i][0],&a[i][1],&a[i][2],&a[i][3]);
        s[i]--,a[i][0]--,a[i][1]--,a[i][2]--,a[i][3]--;
        st+=(s[i]<<i*2);
    }
    memset(ds,0x3f,sizeof(ds));
    memset(dt,0x3f,sizeof(dt));
    ds[st]=0; 
    dt[0]=0; 
    qs.push(st);
    qt.push(0);
    while(1){
        int x=qs.front();
        qs.pop();
//        printf("x %d\n",x); 
        for(int i=0;i<12;i++){
//        	printf("%d %d\n",x,i); 
            int nxt=chg(x,i,1),p=(x>>i*2)%4;
            if(a[i][p]!=i){
//				printf("chg %d %d\n",nxt,a[i][p]);
                nxt=chg(nxt,a[i][p],1);
            }
//            printf("%d\n",nxt); 
            if(ds[nxt]>ds[x]+1){
                ds[nxt]=ds[x]+1;
                qs.push(nxt);
                ls[nxt]=x;
                lsb[nxt]=i+1;
                if(ds[nxt]+dt[nxt]<1e9){
        			printf("%d\n",ds[nxt]+dt[nxt]);
        			for(int j=nxt;j!=st;j=ls[j])
        				path[++top]=lsb[j];
        			reverse(path+1,path+top+1);
        			for(int j=nxt;j!=0;j=lt[j])
        				path[++top]=ltb[j];
        			for(int j=1;j<=top;j++)
        				printf("%d ",path[j]);
        			puts("");
        			return 0;
				}
            }
        }
        x=qt.front();
        qt.pop();
        for(int i=0;i<12;i++){
        	int nxt=chg(x,i,-1),p=(x>>i*2)%4;
        	p=(p+3)%4; 
        	if(a[i][p]!=i)
        		nxt=chg(nxt,a[i][p],-1);
        	if(dt[nxt]>dt[x]+1){
        		dt[nxt]=dt[x]+1;
        		qt.push(nxt);
        		lt[nxt]=x;
        		ltb[nxt]=i+1;
			}
		}
    }
    return 0;
}
